import{v as D,R as M,b as X,a as Y,e as j,t as x,c as z,d as Z,f as ee,g as ae,M as ne,U as re,L as te}from"./index-CDUqjauA.js";const v="2026-07",f="Partnerjurist (utkast, ej granskad)",V={"K-INGRESS-01":{id:"K-INGRESS-01",rubrik:"Ingress",text:"Jag, {{testator_namn}}{{testator_pnr}}, förklarar härmed att detta är min yttersta vilja och mitt testamente.",klarsprak:"Öppningen som gör dokumentet till ett testamente i lagens mening.",lagreferens:"ÄB 10 kap.",forfattare:f,version:v,dokument:"testamente"},"K-ATERKALL-01":{id:"K-ATERKALL-01",rubrik:"Återkallelse av tidigare förordnanden",text:"Jag återkallar härmed samtliga tidigare av mig upprättade testamenten och kodicill, dock med undantag för sådana förordnanden som uttryckligen anges bestå.",klarsprak:"Ditt nya testamente ersätter alla gamla. Förstör fysiskt gamla original.",lagreferens:"ÄB 10:5",forfattare:f,version:v,dokument:"testamente"},"K-FORDELNING-PROC-01":{id:"K-FORDELNING-PROC-01",rubrik:"Fördelning i andelar",text:"Min kvarlåtenskap ska fördelas enligt följande: {{fordelningslista}}.",klarsprak:"Här anges vem som får hur stor andel av din kvarlåtenskap.",lagreferens:"ÄB 9–11 kap.",forfattare:f,version:v,dokument:"testamente"},"K-ENSKILD-01":{id:"K-ENSKILD-01",rubrik:"Enskild egendom",text:"All egendom som tillfaller mottagare enligt detta testamente, liksom avkastning därav och vad som träder i egendomens ställe, ska utgöra mottagarens enskilda egendom.",klarsprak:"Standardskydd (opt-out): arvet ingår inte i bodelning om mottagaren skiljer sig.",lagreferens:"ÄktB 7:2",forfattare:f,version:v,dokument:"testamente"},"K-EFTERLEV-FRIFORF-01":{id:"K-EFTERLEV-FRIFORF-01",rubrik:"Efterlevandeskydd — fri förfoganderätt",text:"Egendom som tillfaller min {{partner_typ}} {{partner_namn}} ska innehas med fri förfoganderätt. Vid dennes frånfälle ska kvarvarande egendom tillfalla {{efterarvingar}}.",klarsprak:"Din partner kan använda och sälja egendomen men inte testamentera bort den — den går vidare till efterarvingarna.",lagreferens:"ÄB 3:1–2",forfattare:f,version:v,dokument:"testamente"},"K-EFTERLEV-FULL-01":{id:"K-EFTERLEV-FULL-01",rubrik:"Efterlevandeskydd — full äganderätt",text:"Egendom som tillfaller min {{partner_typ}} {{partner_namn}} ska innehas med full äganderätt.",klarsprak:"Din partner får egendomen utan begränsning och kan även testamentera bort den.",lagreferens:"ÄB 3 kap.",forfattare:f,version:v,dokument:"testamente"},"K-SARKULL-VADJAN-01":{id:"K-SARKULL-VADJAN-01",rubrik:"Vädjan till särkullbarn",text:"Det är min önskan och vädjan — ej ett villkor — att {{sarkullbarn_namn}} avstår sitt arv till förmån för min efterlevande {{partner_typ}} enligt ÄB 3:9, för att i stället erhålla efterarv vid dennes frånfälle.",klarsprak:"En vädjan, aldrig tvingande: särkullbarn väljer själva om de vill vänta på sitt arv.",lagreferens:"ÄB 3:9",forfattare:f,version:v,dokument:"testamente"},"K-LAGLOTT-01":{id:"K-LAGLOTT-01",rubrik:"Laglottsförbehåll",text:"I den mån förordnande i detta testamente inkräktar på bröstarvinges laglott, ska förordnandet jämkas endast i den utsträckning som krävs för att laglotten ska kunna utgå.",klarsprak:"Om fördelningen kränker ett barns laglott jämkas den så lite som möjligt — resten av din vilja står fast.",lagreferens:"ÄB 7:1, 7:3",forfattare:f,version:v,dokument:"testamente"},"K-EXEKUTOR-01":{id:"K-EXEKUTOR-01",rubrik:"Testamentsexekutor",text:"Till testamentsexekutor utser jag {{exekutor_namn}}, som ska förvalta och skifta min kvarlåtenskap.",klarsprak:"En utsedd person sköter boet — minskar risken för syskonkonflikter.",lagreferens:"ÄB 19 kap.",forfattare:f,version:v,dokument:"testamente"},"K-FORMYNDARE-01":{id:"K-FORMYNDARE-01",rubrik:"Önskemål om vårdnadshavare",text:"För det fall båda vårdnadshavarna avlider innan våra barn uppnått myndig ålder är det min önskan att {{formyndare_namn}} anförtros vårdnaden. Jag är medveten om att domstol beslutar i frågan men ber att detta önskemål tillmäts betydelse.",klarsprak:"Domstol beslutar om vårdnad, men förälderns önskemål ska tillmätas betydelse — därför skrivs det in.",lagreferens:"FB 6:10 a",forfattare:f,version:v,dokument:"testamente"},"K-SARSKFORV-01":{id:"K-SARSKFORV-01",rubrik:"Särskild förvaltning",text:"Egendom som tillfaller omyndig eller ung mottagare ska stå under särskild förvaltning av {{forvaltare_namn}}, utan överförmyndarkontroll, till dess mottagaren fyllt {{utbetalningsalder}} år. Förvaltaren ska årligen redovisa förvaltningen till mottagaren.",klarsprak:"Sveriges närmaste motsvarighet till en trust: du väljer vem som förvaltar barnens arv och vid vilken ålder det betalas ut — i stället för allt på 18-årsdagen.",lagreferens:"FB 12:1 st 2",forfattare:f,version:v,dokument:"testamente"},"K-VITTNESMENING-01":{id:"K-VITTNESMENING-01",rubrik:"Vittnesmening",text:"Att {{testator_namn}}, som vi personligen känner, denna dag vid sunt och fullt förstånd och av fri vilja i bägge våra samtidiga närvaro undertecknat detta testamente, intygar vi särskilt anmodade vittnen: {{vittne1}} samt {{vittne2}}.",klarsprak:"Vittnesmeningen med båda vittnenas intyg — krävs för giltighet.",lagreferens:"ÄB 10:1–2",forfattare:f,version:v,dokument:"testamente"},"K-LAGVAL-01":{id:"K-LAGVAL-01",rubrik:"Lagval",text:"I enlighet med artikel 22 i EU:s arvsförordning (650/2012) väljer jag att lagen i {{lagval_land}}, där jag är medborgare, ska tillämpas på arvet efter mig i dess helhet.",klarsprak:"Låser hela arvet till svensk lag även om du flyttar utomlands — planens viktigaste internationella klausul.",lagreferens:"Förordning (EU) 650/2012 art. 22",forfattare:f,version:v,dokument:"testamente"},"K-RACKVIDD-01":{id:"K-RACKVIDD-01",rubrik:"Räckvidd — universell",text:"Detta testamente omfattar all min egendom, var den än är belägen.",klarsprak:"Testamentet gäller allt du äger, i alla länder.",lagreferens:"—",forfattare:f,version:v,dokument:"testamente"},"K-RACKVIDD-01-EXKL":{id:"K-RACKVIDD-01-EXKL",rubrik:"Räckvidd — undantag för situs-egendom",text:"Detta testamente omfattar all min egendom med undantag för fast egendom i {{situs_lander}}, vilken regleras i separat testamente upprättat för respektive land.",klarsprak:"Huvudtestamentet lämnar medvetet utlandsfastigheten till det lokala testamentet — förhindrar kollision.",lagreferens:"—",forfattare:f,version:v,dokument:"testamente"},"K-RACKVIDD-02":{id:"K-RACKVIDD-02",rubrik:"Räckvidd — situs-begränsad",text:"Detta testamente omfattar endast min egendom belägen i {{situs_land}} och ingen annan egendom.",klarsprak:"Det lokala testamentet gäller bara egendomen i det landet.",lagreferens:"—",forfattare:f,version:v,dokument:"situs"},"K-ICKEATERKALL-01":{id:"K-ICKEATERKALL-01",rubrik:"Icke-återkallelse",text:"Detta testamente återkallar inte mitt testamente avseende övrig egendom, daterat {{huvudtestamente_datum}}, vilket ska äga fortsatt giltighet.",klarsprak:"Klassiska felet — att ett utländskt testamente råkar återkalla det svenska — blockeras uttryckligen.",lagreferens:"—",forfattare:f,version:v,dokument:"situs"},"K-NORDKONV-01":{id:"K-NORDKONV-01",rubrik:"Nordisk anknytning",text:"För arvet efter mig med anknytning till annat nordiskt land gäller den nordiska arvskonventionens lagvalsregler.",klarsprak:"Klargör att inomnordiska fall följer den nordiska arvskonventionen.",lagreferens:"Nordiska arvskonventionen (SÖ 1935:17, ändrad 2012)",forfattare:f,version:v,dokument:"testamente"},"K-FFM-INGRESS-01":{id:"K-FFM-INGRESS-01",rubrik:"Framtidsfullmakt",text:"Jag, {{testator_namn}}{{testator_pnr}}, lämnar härmed framtidsfullmakt till {{fullmaktshavare_lista}} att företräda mig i {{omfattning}} angelägenheter för det fall jag på grund av sjukdom, psykisk störning, försvagat hälsotillstånd eller liknande varaktigt saknar förmåga att ta hand om dessa.",klarsprak:"Du väljer själv vem som tar besluten om du en dag inte kan — annars kan det bli en god man utsedd av kommunen.",lagreferens:"Lag (2017:310) 1–5 §§",forfattare:f,version:v,dokument:"framtidsfullmakt"},"K-FFM-IKRAFT-01":{id:"K-FFM-IKRAFT-01",rubrik:"Ikraftträdande",text:"Fullmaktshavaren avgör när fullmakten träder i kraft. Fullmaktshavaren får även begära att frågan prövas av tingsrätten.",klarsprak:"Fullmakten börjar gälla först när du varaktigt inte längre kan fatta besluten själv.",lagreferens:"Lag (2017:310) 9–11 §§",forfattare:f,version:v,dokument:"framtidsfullmakt"},"K-FFM-GRANSKARE-01":{id:"K-FFM-GRANSKARE-01",rubrik:"Granskare",text:"Till granskare utser jag {{granskare_namn}}. Fullmaktshavaren ska på begäran redovisa sitt uppdrag till granskaren.",klarsprak:"En utsedd person får insyn i hur fullmakten används — motsvarar trustens 'trustee oversight'.",lagreferens:"Lag (2017:310) 23 §",forfattare:f,version:v,dokument:"framtidsfullmakt"},"K-FFM-ATERKALL-01":{id:"K-FFM-ATERKALL-01",rubrik:"Återkallelse",text:"Denna framtidsfullmakt kan återkallas av mig så länge jag har förmåga därtill. Tidigare framtidsfullmakter återkallas härmed.",klarsprak:"Du kan ångra dig så länge du är beslutsförmögen.",lagreferens:"Lag (2017:310) 8 §",forfattare:f,version:v,dokument:"framtidsfullmakt"},"K-FFM-VITTNE-01":{id:"K-FFM-VITTNE-01",rubrik:"Bevittning (framtidsfullmakt)",text:"Att {{testator_namn}} denna dag med sunt och fullt förstånd undertecknat denna framtidsfullmakt i bägge våra samtidiga närvaro intygar: {{vittne1}} samt {{vittne2}}. Fullmaktshavaren har inte bevittnat handlingen.",klarsprak:"Två vittnen krävs — och fullmaktshavaren själv får inte vara ett av dem.",lagreferens:"Lag (2017:310) 4 §",forfattare:f,version:v,dokument:"framtidsfullmakt"},"K-SAMBO-01":{id:"K-SAMBO-01",rubrik:"Samboavtal — bodelning avtalas bort",text:"Vi, {{testator_namn}} och {{partner_namn}}, avtalar att sambolagens regler om bodelning inte ska gälla i vårt samboförhållande. {{undantag}}",klarsprak:"Ni väljer själva vad som ska delas om förhållandet upphör — i stället för sambolagens hälftendelning av bostad och bohag.",lagreferens:"SamboL 9 §",forfattare:f,version:v,dokument:"samboavtal"}};function se(r){return V[r]??null}con